options.customCss:
/* =========================================================
   FONT
   ========================================================= */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&display=swap');


/* =========================================================
   LIGHT THEME (DEFAULT)
   ========================================================= */
:root {
  /* ---------- COLORS ---------- */
  --chat--color-primary: #2563eb;
  --chat--color-primary-shade-50: #1d4ed8;
  --chat--color-primary-shade-100: #1e40af;

  --chat--color-secondary: #10b981;
  --chat--color-secondary-shade-50: #059669;

  --chat--color-white: #ffffff;
  --chat--color-light: #f8fafc;
  --chat--color-light-shade-50: #e5e7eb;
  --chat--color-light-shade-100: #d1d5db;

  --chat--color-medium: #cbd5e1;
  --chat--color-dark: #0f172a;
  --chat--color-disabled: #cbd5e1;
  --chat--color-typing: #475569;

  /* ---------- TYPOGRAPHY ---------- */
  --chat--font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --chat--message--font-size: 1rem;
  --chat--message-line-height: 1.65;
  --chat--heading--font-size: 1.3em;
  --chat--subtitle--font-size: 0.95em;
  --chat--input--font-size: 1rem;
  --chat--input--line-height: 1.6;

  /* ---------- LAYOUT ---------- */
  --chat--spacing: 1.1rem;
  --chat--border-radius: 0.75rem;

  /* ---------- WINDOW ---------- */
  --chat--window--width: 460px;
  --chat--window--height: 680px;
  --chat--window--border: 1px solid var(--chat--color-light-shade-50);

  /* ---------- HEADER ---------- */
  --chat--header--background: var(--chat--color-dark);
  --chat--header--color: var(--chat--color-light);

  /* ---------- BODY ---------- */
  --chat--body--background: var(--chat--color-light);

  /* ---------- MESSAGES ---------- */
  --chat--message--bot--background: var(--chat--color-white);
  --chat--message--bot--color: var(--chat--color-dark);
  --chat--message--bot--border: 1px solid var(--chat--color-light-shade-50);

  --chat--message--user--background: var(--chat--color-secondary);
  --chat--message--user--color: var(--chat--color-white);

  /* ---------- INPUT ---------- */
  --chat--input--background: var(--chat--color-white);
  --chat--input--text-color: var(--chat--color-dark);
  --chat--input--placeholder--color: #94a3b8;
}


/* =========================================================
   DARK MODE (AUTOMATIC)
   ========================================================= */
@media (prefers-color-scheme: dark) {
  :root {
    --chat--color-white: #020617;
    --chat--color-light: #020617;
    --chat--color-light-shade-50: #1e293b;
    --chat--color-light-shade-100: #334155;

    --chat--color-dark: #e5e7eb;
    --chat--color-medium: #475569;
    --chat--color-typing: #94a3b8;

    --chat--body--background: #020617;

    --chat--header--background: #020617;
    --chat--header--color: #e5e7eb;

    --chat--message--bot--background: #020617;
    --chat--message--bot--color: #e5e7eb;
    --chat--message--bot--border: 1px solid #1e293b;

    --chat--message--user--background: #10b981;
    --chat--message--user--color: #020617;

    /* INPUT – FIX DEFINITIVO */
    --chat--input--background: #020617;
    --chat--input--text-color: #e5e7eb;
    --chat--input--placeholder--color: #64748b;
  }
}


/* =========================================================
   BASE ELEMENTS
   ========================================================= */
.chat-message {
  max-width: 70%;
  font-family: var(--chat--font-family);
  font-size: var(--chat--message--font-size);
  line-height: var(--chat--message-line-height);
  letter-spacing: 0.01em;
}

.chat-message.bot {
  font-weight: 500;
}

.chat-message.user {
  font-weight: 400;
}

.chat-header,
.chat-header * {
  font-family: var(--chat--font-family);
  font-weight: 600;
}


/* =========================================================
   INPUT – VISIBILITY GUARANTEED
   ========================================================= */
.chat-input,
textarea,
input {
  font-family: var(--chat--font-family);
  font-size: var(--chat--input--font-size);
  line-height: var(--chat--input--line-height);
  color: var(--chat--input--text-color);
  background-color: var(--chat--input--background);
  caret-color: var(--chat--input--text-color);
}

.chat-input::placeholder,
textarea::placeholder,
input::placeholder {
  color: var(--chat--input--placeholder--color);
}


/* =========================================================
   RAG – SOURCE / DOCUMENT BADGE
   ========================================================= */
.rag-source {
  display: inline-block;
  margin-left: 0.4rem;
  padding: 0.15rem 0.5rem;
  font-size: 0.75rem;
  font-weight: 600;
  border-radius: 999px;
  background: rgba(37, 99, 235, 0.1);
  color: var(--chat--color-primary);
}


/* =========================================================
   RAG – DOCUMENT TYPE ICONS
   ========================================================= */
.rag-doc {
  font-weight: 500;
}

.rag-doc::before {
  margin-right: 0.35rem;
}

.rag-doc.pdf::before { content: "📄"; }
.rag-doc.sheet::before { content: "📊"; }
.rag-doc.text::before { content: "📑"; }


/* =========================================================
   RAG – CONFIDENCE / MATCH SCORE
   ========================================================= */
.rag-confidence {
  display: inline-flex;
  align-items: center;
  margin-left: 0.5rem;
  padding: 0.15rem 0.45rem;
  font-size: 0.75rem;
  font-weight: 600;
  border-radius: 999px;
  background: rgba(15, 23, 42, 0.06);
  color: #334155;
}

.rag-confidence::before {
  content: "match";
  margin-right: 0.3rem;
  opacity: 0.7;
}

.rag-confidence.high {
  background: rgba(16, 185, 129, 0.15);
  color: #065f46;
}

.rag-confidence.medium {
  background: rgba(234, 179, 8, 0.15);
  color: #92400e;
}

.rag-confidence.low {
  background: rgba(239, 68, 68, 0.15);
  color: #7f1d1d;
}


/* =========================================================
   RAG – NUMERIC CITATIONS (PAPER STYLE)
   ========================================================= */
.rag-ref {
  display: inline-block;
  margin-left: 0.15rem;
  padding: 0 0.35rem;
  font-size: 0.75rem;
  font-weight: 600;
  border-radius: 4px;
  color: var(--chat--color-primary);
  text-decoration: none;
  border: 1px solid currentColor;
}

.rag-ref:hover {
  background: var(--chat--color-primary);
  color: #ffffff;
}


/* =========================================================
   RAG – INLINE DOCUMENT PREVIEW
   ========================================================= */
.rag-preview {
  margin-top: 0.75rem;
  border-radius: 0.5rem;
  overflow: hidden;
  border: 1px solid var(--chat--color-light-shade-50);
}

.rag-preview summary {
  padding: 0.5rem 0.75rem;
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  background: var(--chat--color-light);
}

.rag-preview summary:hover {
  background: var(--chat--color-light-shade-50);
}

.rag-preview iframe {
  width: 100%;
  height: 320px;
  border: none;
}


/* =========================================================
   CODE BLOCKS
   ========================================================= */
.chat-message pre {
  margin-top: 0.75rem;
  padding: 0.75rem;
  border-radius: 0.5rem;
  background: rgba(0, 0, 0, 0.05);
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
  font-size: 0.9em;
}

@media (prefers-color-scheme: dark) {
  .chat-message pre {
    background: rgba(255, 255, 255, 0.06);
  }
}
